#include <vector>
#include <numeric>
#include <algorithm>

using namespace std;

/**
 * @brief Solves the unimodal array splitting problem.
 * 
 * @param nums The unimodal array of Int64.
 * @return int64 0 if increasing sum is larger, 1 if decreasing sum is larger, -1 if equal.
 */
long long solve(const std::vector<long long>& nums) {
    int n = nums.size();

    if (n < 3) {
        // Should not happen based on constraints (N >= 3), but good practice.
        return 0; 
    }

    // Step 1: Find the peak index P using Binary Search (O(log N))
    int l = 0;
    int r = n - 1;
    int peak_index = 0;

    while (l <= r) {
        if (l == r) {
            peak_index = l;
            break;
        }

        int mid = l + (r - l) / 2;

        // If we are on the increasing slope (or at the start, and next is larger)
        if (nums[mid] < nums[mid + 1]) {
            l = mid + 1; // Peak must be to the right
        } else {
            // If nums[mid] > nums[mid+1], we are on the decreasing slope or at the peak
            r = mid; // Peak could be mid, or to the left
        }
    }

    // If the loop finishes due to L > R (which shouldn't happen with the above while condition), 
    // the last determined peak_index (L or R) should be correct.
    // Since we used l <= r and break when l=r, peak_index holds the correct value.
    if (l == n) { // Edge case check for strictly increasing sequence ending at n-1
         peak_index = n - 1;
    }


    // Step 2: Calculate sums (O(N))
    long long sum_inc = 0;
    // Increasing part: 0 to P (inclusive)
    for (int i = 0; i <= peak_index; ++i) {
        sum_inc += nums[i];
    }

    long long sum_dec = 0;
    // Decreasing part: P to N-1 (inclusive)
    for (int i = peak_index; i < n; ++i) {
        sum_dec += nums[i];
    }

    // Step 3: Compare and return
    if (sum_inc > sum_dec) {
        return 0;
    } else if (sum_dec > sum_inc) {
        return 1;
    } else {
        return -1;
    }
}
